static int run_lookup(const char *name) {
    if (name[0] == '-') {
        fprintf(stderr, "Invalid host\n");
        return 1;
    }
    for (const unsigned char *p = (const unsigned char *)name; *p; ++p) {
        if (!(isalnum(*p) || *p == '.' || *p == '-')) {
            fprintf(stderr, "Invalid host\n");
            return 1;
        }
    }

    int pipefd[2];
    if (pipe(pipefd) < 0) {
        perror("pipe");
        return 1;
    }

    pid_t pid = fork();
    if (pid < 0) {
        perror("fork");
        close(pipefd[0]);
        close(pipefd[1]);
        return 1;
    }

    if (pid == 0) {
        close(pipefd[0]);
        if (dup2(pipefd[1], STDOUT_FILENO) < 0) {
            perror("dup2");
            _exit(127);
        }
        close(pipefd[1]);

        execlp("nslookup", "nslookup", name, (char *)NULL);
        perror("execlp");
        _exit(127);
    }

    close(pipefd[1]);

    FILE *fp = fdopen(pipefd[0], "r");
    if (!fp) {
        perror("fdopen");
        close(pipefd[0]);
        (void)waitpid(pid, NULL, 0);
        return 1;
    }

    char buf[256];
    while (fgets(buf, sizeof(buf), fp)) {
        fputs(buf, stdout);
    }

    fclose(fp);
    int status = 0;
    (void)waitpid(pid, &status, 0);
    return (WIFEXITED(status) && WEXITSTATUS(status) == 0) ? 0 : 1;
}
